listitem.programlisting:
mongodb().poll {
  connect {
MongoClients.create("mongodb://localhost:${mongoDbPort}/?streamType=netty")
  }
  search {
    database = "the-db"
    collection = "moves"
    query = Document().append("action", "IN")
    sort = linkedMapOf("timestamp" to Sorting.ASC)
    tieBreaker = "timestamp"
  }
  pollDelay(Duration.ofSeconds(2))
}

mongodb().save {
  connect {
    MongoClients.create()
  }
  query {
    database = databaseName
    collection = collectionName
    records = recordSupplier
  }
	monitoring {
	  events = false
    meters = true
  }
}

mongodb().search {
	connect {
    MongoClients.create()
  }
  search {
    database = { _, _ -> "db" }
    collection = { _, _ -> "col" }
    query = { _, _ -> Document() }
    sort = { _, _ -> linkedMapOf("asc" to Sorting.ASC, "desc" to Sorting.DESC) }
  }
  monitoring {
	  events = false
    meters = true
  }
}
